SELECT matches.id, matches.challenger_id, players.username, matches.challenger_score, matches.match_status
FROM matches
JOIN players ON matches.challenger_id = players.player_id;

SELECT username, email 
FROM players 
WHERE player_id NOT IN (SELECT challenger_id FROM matches);

SELECT MIN(timestamp) 
FROM notifications 
WHERE player_id = (SELECT player_id FROM players WHERE username = 'player_one');

SELECT username, profile_image_url
FROM players
WHERE account_status NOT IN ('suspended', 'banned');

SELECT AVG(JULIANDAY('now') - JULIANDAY(creation_date)) AS average_days
FROM challenges
WHERE status = 'accepted';

SELECT game_id, AVG(match_duration) AS average_match_duration
FROM matches
GROUP BY game_id;
